+// ─── Status effect drawing ───────────────────────────────────────────────
+
+function drawStatusEffect(
+  ctx: CanvasRenderingContext2D,
+  x: number,
+  y: number,
+  status: string,
+  frame: number,
+) {
+  switch (status) {
+    case 'idle': {
+      // subtle pulsing white glow (opacity oscillates 0.1-0.3)
+      const opacity = 0.2 + 0.1 * Math.sin(frame * 0.1);
+      ctx.save();
+      ctx.shadowColor = `rgba(255,255,255,${opacity.toFixed(3)})`;
+      ctx.shadowBlur = 8;
+      ctx.fillStyle = `rgba(255,255,255,${opacity.toFixed(3)})`;
+      // Draw a white rectangle slightly bigger than character sprite area (16x16)
+      ctx.fillRect(x - 2, y - 2, 20, 20);
+      ctx.restore();
+      break;
+    }
+    case 'working': {
+      // golden sparkle particles around character
+      const id = `working-${x}-${y}`;
+      // Spawn new particles randomly
+      if (Math.random() < 0.15) {
+        const px = x + 8 + (Math.random() - 0.5) * 20;
+        const py = y + 8 + (Math.random() - 0.5) * 20;
+        spawnParticle(id, px, py, '#f1c40f', (Math.random() - 0.5) * 0.3, -0.3 - Math.random() * 0.3, 2, 30);
+      }
+      updateAndDrawParticles(ctx, id);
+      break;
+    }
+    case 'reviewing': {
+      // magnifying glass icon above head
+      ctx.save();
+      ctx.strokeStyle = '#555';
+      ctx.lineWidth = 2;
+      ctx.beginPath();
+      // circle lens
+      ctx.arc(x + 8, y - 6, 5, 0, Math.PI * 2);
+      ctx.stroke();
+      // handle
+      ctx.beginPath();
+      ctx.moveTo(x + 12, y - 2);
+      ctx.lineTo(x + 16, y + 2);
+      ctx.stroke();
+      ctx.restore();
+      break;
+    }
+    case 'stalled': {
+      // red pulsing outline
+      const opacity = 0.3 + 0.2 * Math.sin(frame * 0.15);
+      ctx.save();
+      ctx.strokeStyle = `rgba(255,0,0,${opacity.toFixed(3)})`;
+      ctx.lineWidth = 3;
+      ctx.shadowColor = `rgba(255,0,0,${opacity.toFixed(3)})`;
+      ctx.shadowBlur = 8;
+      ctx.strokeRect(x - 1, y - 1, 18, 18);
+      ctx.restore();
+      break;
+    }
+    case 'failed': {
+      // dark gray desaturation overlay
+      ctx.save();
+      ctx.fillStyle = 'rgba(50,50,50,0.5)';
+      ctx.fillRect(x, y, 16, 16);
+      ctx.restore();
+      break;
+    }
+  }
+}
